import urllib.request, urllib.error, json, getpass
BASE='https://app.vpid.org'
def api(path, token=None, method='GET', data=None):
    url=BASE+'/api'+path; h={'Content-Type':'application/json'}
    if token: h['Authorization']='Bearer '+token
    body=json.dumps(data).encode() if data else None
    req=urllib.request.Request(url, body, h, method=method)
    try:
        r=urllib.request.urlopen(req, timeout=20); return json.loads(r.read()), r.status
    except urllib.error.HTTPError as e:
        try: return json.loads(e.read()), e.code
        except: return {}, e.code
